import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void encodeTypical() {
        assertEquals("1,-2,3", new Solution().encode(new int[]{1, -2, 3}));
    }

    @Test
    void encodeEmpty() {
        assertEquals("", new Solution().encode(new int[]{}));
    }

    @Test
    void encodeSingleElement() {
        assertEquals("42", new Solution().encode(new int[]{42}));
    }

    @Test
    void roundTripTypical() {
        Solution sol = new Solution();
        int[] original = {1, -2, 3, 0, Integer.MIN_VALUE, Integer.MAX_VALUE};
        assertArrayEquals(original, sol.decode(sol.encode(original)));
    }

    @Test
    void roundTripEmpty() {
        Solution sol = new Solution();
        int[] original = {};
        assertArrayEquals(original, sol.decode(sol.encode(original)));
    }

    @Test
    void roundTripSingleNegative() {
        Solution sol = new Solution();
        int[] original = {-999};
        assertArrayEquals(original, sol.decode(sol.encode(original)));
    }

    @Test
    void decodeEmptyString() {
        assertArrayEquals(new int[]{}, new Solution().decode(""));
    }
}
